={{
{
  inputs: {
    lead_message: $json.lead_message || '',
    julia_response: $json.julia_response || '',
    lead_status: $json.lead_status || '',
    last_intent: $json.last_intent || '',
    lead_summary: $json.lead_summary || '',
    last_ai_message: $json.last_ai_message || '',
    system_event: $json.system_event || '',
    option_1_start: $json.option_1_start || '',
    option_2_start: $json.option_2_start || '',
    selected_option_start: $json.selected_option_start || '',
    email: $json.email || '',
    correction_reason: $json.correction_reason || '',
    correction_instruction: $json.correction_instruction || '',
    history_from_crm: $json.history_for_crm || ''
  },
  query: $json.atlas_query || 'validar resposta da Julia',
  response_mode: 'streaming',
  user: $json.phone || ''
}
}}

parameters.jsCode:
const raw = $json.data || $json.body || $json.response || $json.output || '';
const text = Array.isArray(raw) ? raw.join('\n') : String(raw);

const events = text
  .split('\n\n')
  .map(block => block.trim())
  .filter(Boolean);

let atlasAnswer = '';
let workflowAnswer = '';
let llmText = '';

for (const block of events) {
  const lines = block.split('\n');
  const dataLine = lines.find(line => line.startsWith('data: '));
  if (!dataLine) continue;

  const jsonStr = dataLine.replace(/^data:\s*/, '').trim();
  if (!jsonStr || jsonStr === '[DONE]') continue;

  let evt;
  try {
    evt = JSON.parse(jsonStr);
  } catch {
    continue;
  }

  if (evt.event === 'message' && typeof evt.answer === 'string') {
    llmText += evt.answer;
  }

  if (
    evt.event === 'node_finished' &&
    evt.data &&
    evt.data.node_type === 'answer' &&
    evt.data.outputs &&
    typeof evt.data.outputs.answer === 'string'
  ) {
    atlasAnswer = evt.data.outputs.answer;
  }

  if (
    evt.event === 'workflow_finished' &&
    evt.data &&
    evt.data.outputs &&
    typeof evt.data.outputs.answer === 'string'
  ) {
    workflowAnswer = evt.data.outputs.answer;
  }
}

const finalRaw = workflowAnswer || atlasAnswer || llmText || '';

let parsed;
try {
  parsed = JSON.parse(finalRaw);
} catch (e) {
  parsed = {
    decision: 'REPROCESSAR_CONTEXTO',
    reason: 'Falha ao converter resposta do Atlas em JSON.',
    corrected_message: '',
    correction_instruction: 'Responder novamente respeitando o estágio atual da conversa, pois a validação falhou no parse.'
  };
}

return [
  {
    json: {
      atlas_raw_answer: finalRaw,
      atlas_decision: parsed.decision || '',
      atlas_reason: parsed.reason || '',
      atlas_corrected_message: parsed.corrected_message || '',
      atlas_correction_instruction: parsed.correction_instruction || '',
      atlas_validated: !!parsed.decision
    }
  }
];

const item = $json;

const decision = String(item.atlas_decision || '').trim();
const leadStatus = String(item.lead_status || '').trim();
const lastIntent = String(item.last_intent || '').trim();
const leadSummary = String(item.lead_summary || '').trim();
const leadMessage = String(item.lead_message || '').trim().toLowerCase();
const correctionInstruction = String(item.atlas_correction_instruction || item.correction_instruction || '').trim();
const historyForCrm = String(item.history_for_crm || '').trim().toLowerCase();

function upsertSummary(summary, field, value) {
  if (!summary) return `${field}: ${value};`;
  const regex = new RegExp(`${field}:\\s*[^;]*`, 'i');
  if (regex.test(summary)) {
    return summary.replace(regex, `${field}: ${value}`);
  }
  return `${summary.trim()} ${field}: ${value};`.trim();
}

function buildOutput(message, status, intent, summary, source = 'deterministic_handler') {
  const raw = `${message}

#STATUS:${status}
#LAST_INTENT:${intent}
#LEAD_SUMMARY:${summary}`;

  return {
    ...item,
    handler_resolved: true,
    handler_source: source,
    final_answer_raw: raw,
    final_answer: message,
    final_status: status,
    final_last_intent: intent,
    final_lead_summary: summary
  };
}

function containsAny(text, terms) {
  return terms.some(term => text.includes(term));
}

// Sinais de que o lead ainda vai verificar e não quer responder agora
const leadPostponedDecision = containsAny(leadMessage, [
  'vou ver',
  'vejo',
  'te aviso',
  'depois te aviso',
  'alinho com vc',
  'alinho com você',
  'depois vejo',
  'vou confirmar',
  'vou verificar',
  'vou checar',
  'deixa eu ver',
  'deixa eu verificar'
]);

// Sinais de conflito de agenda
const leadHasScheduleConflict = containsAny(leadMessage, [
  'ruim por causa do trabalho',
  'por causa do trabalho',
  'esse horario',
  'esse horário',
  'não consigo nesse horario',
  'nao consigo nesse horario',
  'não consigo nesse horário',
  'não dá nesse horário',
  'nao da nesse horario',
  'não dá pra mim',
  'não funciona pra mim',
  'nao funciona pra mim'
]);

// Ver se a Julia já pediu novo horário antes
const alreadyAskedForNewDay = containsAny(historyForCrm, [
  'pode me sugerir um dia e horário',
  'que dia da semana é melhor pra você',
  'me fala um período melhor',
  'qual dia funciona melhor',
  'qual dia e horário'
]);

let updatedSummary = leadSummary;

// 1) CASO MAIS IMPORTANTE:
// Lead pediu novos horários, mas respondeu que vai ver depois.
// Aqui NÃO pergunta de novo.
if (
  (leadStatus === 'SOLICITAR_NOVAS_OPCOES' || lastIntent === 'PEDIU_OUTROS_HORARIOS') &&
  leadPostponedDecision
) {
  updatedSummary = upsertSummary(
    updatedSummary,
    'Último contexto',
    'lead informou que vai verificar um dia melhor antes de sugerir nova disponibilidade'
  );

  updatedSummary = upsertSummary(
    updatedSummary,
    'Próxima etapa',
    'aguardar o lead retornar com um dia ou horário melhor'
  );

  return [
    {
      json: buildOutput(
        'Perfeito. Quando conseguir definir um dia melhor, me avisa que eu verifico as opções de horário pra você.',
        'SOLICITAR_NOVAS_OPCOES',
        'PEDIU_OUTROS_HORARIOS',
        updatedSummary
      )
    }
  ];
}

// 2) Lead está em novos horários e falou que os horários não servem.
// Aqui sim pede o dia.
if (
  (leadStatus === 'SOLICITAR_NOVAS_OPCOES' || lastIntent === 'PEDIU_OUTROS_HORARIOS') &&
  leadHasScheduleConflict
) {
  updatedSummary = upsertSummary(
    updatedSummary,
    'Último contexto',
    'informou que os horários enviados não funcionam por causa do trabalho'
  );

  updatedSummary = upsertSummary(
    updatedSummary,
    'Próxima etapa',
    'aguardar sugestão de dia para verificar nova disponibilidade'
  );

  return [
    {
      json: buildOutput(
        'Sem problema. Qual dia funciona melhor para você? Assim, já vejo as opções de horário.',
        'SOLICITAR_NOVAS_OPCOES',
        'PEDIU_OUTROS_HORARIOS',
        updatedSummary
      )
    }
  ];
}

// 3) Se já pediu dia antes, evita repetir a mesma pergunta.
// Faz uma versão mais suave.
if (
  (leadStatus === 'SOLICITAR_NOVAS_OPCOES' || lastIntent === 'PEDIU_OUTROS_HORARIOS') &&
  alreadyAskedForNewDay
) {
  updatedSummary = upsertSummary(
    updatedSummary,
    'Último contexto',
    'conversa segue em aberto para definição de nova disponibilidade'
  );

  updatedSummary = upsertSummary(
    updatedSummary,
    'Próxima etapa',
    'aguardar o lead sugerir um dia melhor para nova consulta de agenda'
  );

  return [
    {
      json: buildOutput(
        'Sem problema. Me avisa quando tiver um dia melhor pra você que eu verifico as opções de horário.',
        'SOLICITAR_NOVAS_OPCOES',
        'PEDIU_OUTROS_HORARIOS',
        updatedSummary
      )
    }
  ];
}

// 4) Aguardando escolha de horário
if (leadStatus === 'AGUARDANDO_ESCOLHA_HORARIO') {
  updatedSummary = upsertSummary(
    updatedSummary,
    'Último contexto',
    'lead não confirmou nenhuma das opções enviadas'
  );

  updatedSummary = upsertSummary(
    updatedSummary,
    'Próxima etapa',
    'aguardar escolha de horário ou nova janela de disponibilidade'
  );

  return [
    {
      json: buildOutput(
        'Se aqueles horários não funcionarem, me fala qual dia funciona melhor para você que eu verifico as opções de horário.',
        'AGUARDANDO_ESCOLHA_HORARIO',
        lastIntent || 'PREPARAR_AGENDAMENTO',
        updatedSummary
      )
    }
  ];
}

// 5) Horário selecionado, mas sem email
if (leadStatus === 'HORARIO_SELECIONADO' && !item.email) {
  updatedSummary = upsertSummary(
    updatedSummary,
    'Último contexto',
    'lead escolheu um horário e falta confirmar email'
  );

  updatedSummary = upsertSummary(
    updatedSummary,
    'Próxima etapa',
    'coletar email para confirmar agendamento'
  );

  return [
    {
      json: buildOutput(
        'Perfeito. Qual seu melhor email para eu confirmar?',
        'AGUARDANDO_EMAIL',
        'PREPARAR_AGENDAMENTO',
        updatedSummary
      )
    }
  ];
}

// 6) Fallback → manda para IA corretora
return [
  {
    json: {
      ...item,
      handler_resolved: false,
      handler_source: 'fallback_ai',
      rewrite_mode: decision === 'REPROCESSAR_CONTEXTO' ? 'FORTE' : 'NORMAL',
      rewrite_instruction: correctionInstruction || 'Corrigir a resposta respeitando o estado atual da conversa.'
    }
  }
];

const raw =
  $json.output ||
  $json.answer ||
  $json.text ||
  $json.message ||
  '';

const statusMatch = raw.match(/#STATUS:(.*)/);
const intentMatch = raw.match(/#LAST_INTENT:(.*)/);
const summaryMatch = raw.match(/#LEAD_SUMMARY:([\s\S]*)/);

const message = raw
  .replace(/#STATUS:.*$/m, '')
  .replace(/#LAST_INTENT:.*$/m, '')
  .replace(/#LEAD_SUMMARY:[\s\S]*$/m, '')
  .trim();

return [
  {
    json: {
      ...$json,
      final_answer_raw: raw,
      final_answer: message,
      final_status: statusMatch ? statusMatch[1].trim() : '',
      final_last_intent: intentMatch ? intentMatch[1].trim() : '',
      final_lead_summary: summaryMatch ? summaryMatch[1].trim() : '',
      handler_source: 'ai_rewrite',
      handler_resolved: true
    }
  }
];

